"""
questions.py — AQA Python Course question bank
Usage in any notebook:
    from questions import q
    q('u1_l1_q1')
"""
from IPython.display import display, HTML as _HTML
import json as _json


# ── Renderers ─────────────────────────────────────────────────────────────────

def _choice(uid, question, options):
    """Single-answer MCQ."""
    correct = next(v for v, e, c in options if c)
    explanations = {v: e for v, e, c in options}
    radios = "".join(
        f'''<label style="display:block;margin:4px 0;cursor:pointer">
          <input type="radio" name="q{uid}" value="{v.replace('"', '&quot;')}"
                 onchange="_qcheck{uid}(this.value)"> {v}
        </label>''' for v, e, c in options
    )
    display(_HTML(f'''
<div id="q{uid}" style="border:1px solid #ddd;border-radius:6px;padding:14px;margin:8px 0;font-family:sans-serif">
  <p><b>Q.</b> {question}</p>
  {radios}
  <div id="q{uid}_fb" style="margin-top:8px;min-height:24px"></div>
</div>
<script>
  var _q{uid}_correct = {_json.dumps(correct)};
  var _q{uid}_exp = {_json.dumps(explanations)};
  function _qcheck{uid}(val) {{
    var fb = document.getElementById("q{uid}_fb");
    var expl = _q{uid}_exp[val] || "";
    if (val === _q{uid}_correct) {{
      fb.innerHTML = "<span style='color:green'>&#10003; Correct! " + expl + "</span>";
    }} else {{
      fb.innerHTML = "<span style='color:crimson'>&#10007; Not quite. " + expl + "</span>";
    }}
  }}
</script>
'''))


def _multiple(uid, question, options):
    """Multiple-answer MCQ."""
    correct = sorted(v for v, e, c in options if c)
    explanations = {v: e for v, e, c in options}
    values = [v for v, e, c in options]
    cb_ids = [f"q{uid}_cb{i}" for i in range(len(values))]
    boxes = "".join(
        f'''<label style="display:block;margin:4px 0;cursor:pointer">
          <input type="checkbox" id="q{uid}_cb{i}" value="{v.replace('"', '&quot;')}"> {v}
        </label>''' for i, (v, e, c) in enumerate(options)
    )
    display(_HTML(f'''
<div id="q{uid}" style="border:1px solid #ddd;border-radius:6px;padding:14px;margin:8px 0;font-family:sans-serif">
  <p><b>Q.</b> {question}<br><i style="font-size:0.9em">Select all that apply.</i></p>
  {boxes}
  <button onclick="_qcheck{uid}()"
          style="margin-top:10px;padding:4px 14px;cursor:pointer">Check</button>
  <div id="q{uid}_fb" style="margin-top:8px"></div>
</div>
<script>
  var _q{uid}_correct = {_json.dumps(correct)};
  var _q{uid}_exp = {_json.dumps(explanations)};
  var _q{uid}_cbids = {_json.dumps(cb_ids)};
  function _qcheck{uid}() {{
    var selected = _q{uid}_cbids
      .map(function(id) {{ return document.getElementById(id); }})
      .filter(function(cb) {{ return cb.checked; }})
      .map(function(cb) {{ return cb.value; }})
      .sort();
    var lines = [];
    {_json.dumps(values)}.forEach(function(opt) {{
      var expl = _q{uid}_exp[opt] || "";
      var isCorrect = _q{uid}_correct.indexOf(opt) !== -1;
      var isSelected = selected.indexOf(opt) !== -1;
      if (isCorrect && isSelected)
        lines.push("<div style='color:green'>&#10003; <b>" + opt + "</b> &mdash; " + expl + "</div>");
      else if (isCorrect && !isSelected)
        lines.push("<div style='color:orange'>&#9651; <b>" + opt + "</b> &mdash; you missed this. " + expl + "</div>");
      else if (!isCorrect && isSelected)
        lines.push("<div style='color:crimson'>&#10007; <b>" + opt + "</b> &mdash; " + expl + "</div>");
    }});
    var allRight = JSON.stringify(selected) === JSON.stringify(_q{uid}_correct);
    if (allRight) lines.unshift("<div style='color:green;font-weight:bold'>All correct! &#127881;</div>");
    document.getElementById("q{uid}_fb").innerHTML = lines.join("");
  }}
</script>
'''))


def _string(uid, question, correct, explanation):
    """Short text answer."""
    display(_HTML(f'''
<div id="q{uid}" style="border:1px solid #ddd;border-radius:6px;padding:14px;margin:8px 0;font-family:sans-serif">
  <p><b>Q.</b> {question}</p>
  <input id="q{uid}_in" type="text" placeholder="Type your answer..."
         style="padding:4px 8px;width:50%;border:1px solid #ccc;border-radius:4px">
  <button onclick="_qcheck{uid}()"
          style="margin-left:8px;padding:4px 14px;cursor:pointer">Check</button>
  <div id="q{uid}_fb" style="margin-top:8px;min-height:24px"></div>
</div>
<script>
  var _q{uid}_correct = {_json.dumps(correct)};
  var _q{uid}_explanation = {_json.dumps(explanation)};
  function _qcheck{uid}() {{
    var answer = document.getElementById("q{uid}_in").value.trim().toLowerCase();
    var fb = document.getElementById("q{uid}_fb");
    if (answer === "") {{
      fb.innerHTML = "<span style='color:grey'>&#128161; Answer: <b>" + _q{uid}_correct + "</b> &mdash; " + _q{uid}_explanation + "</span>";
    }} else if (answer === _q{uid}_correct.toLowerCase()) {{
      fb.innerHTML = "<span style='color:green'>&#10003; Correct! " + _q{uid}_explanation + "</span>";
    }} else {{
      fb.innerHTML = "<span style='color:crimson'>&#10007; Not quite &mdash; try again, or clear your answer and click Check to reveal.</span>";
    }}
  }}
</script>
'''))


def _reflection(uid, question):
    """Open reflection prompt."""
    display(_HTML(f'''
<div style="border:1px solid #ddd;border-radius:6px;padding:14px;margin:8px 0;font-family:sans-serif;background:#f9f9f9">
  <p><b>Reflection.</b> {question}</p>
  <p style="color:#666;font-size:0.9em">Write your thoughts in the code cell below.</p>
</div>
'''))


# ── Public API ────────────────────────────────────────────────────────────────

def q(name):
    """Display a question by ID, e.g. q('u1_l1_q1')"""
    if name not in _Q:
        print(f"Question '{name}' not found.")
        return
    _Q[name]()


